     300: static int getNextString(
     301:   ParseContext *pParse,                   /* fts3 query parse context */
     302:   const char *zInput, int nInput,         /* Input string */
     303:   Fts3Expr **ppExpr                       /* OUT: expression */
     304: ){
     305:   sqlite3_tokenizer *pTokenizer = pParse->pTokenizer;
     306:   sqlite3_tokenizer_module const *pModule = pTokenizer->pModule;
     307:   int rc;
