     309:   sqlite3_tokenizer_cursor *pCursor = 0;
     310:   char *zTemp = 0;
     311:   i64 nTemp = 0;
     312: 
     313:   const int nSpace = sizeof(Fts3Expr) + SZ_FTS3PHRASE(1);
     314:   int nToken = 0;
     315: 
     316:   /* The final Fts3Expr data structure, including the Fts3Phrase,
     317:   ** Fts3PhraseToken structures token buffers are all stored as a single 
     318:   ** allocation so that the expression can be freed with a single call to
     319:   ** sqlite3_free(). Setting this up requires a two pass approach.
     320:   **
     321:   ** The first pass, in the block below, uses a tokenizer cursor to iterate
     322:   ** through the tokens in the expression. This pass uses fts3ReallocOrFree()
     323:   ** to assemble data in two dynamic buffers:
     324:   **
     325:   **   Buffer p: Points to the Fts3Expr structure, followed by the Fts3Phrase
     326:   **             structure, followed by the array of Fts3PhraseToken 
     327:   **             structures. This pass only populates the Fts3PhraseToken array.
     328:   **
     329:   **   Buffer zTemp: Contains copies of all tokens.
     330:   **
     331:   ** The second pass, in the block that begins "if( rc==SQLITE_DONE )" below,
     332:   ** appends buffer zTemp to buffer p, and fills in the Fts3Expr and Fts3Phrase
     333:   ** structures.
