     339:     for(ii=0; rc==SQLITE_OK; ii++){
     340:       const char *zByte;
     341:       int nByte = 0, iBegin = 0, iEnd = 0, iPos = 0;
     342:       rc = pModule->xNext(pCursor, &zByte, &nByte, &iBegin, &iEnd, &iPos);
     343:       if( rc==SQLITE_OK ){
     344:         Fts3PhraseToken *pToken;
     345: 
     346:         p = fts3ReallocOrFree(p, nSpace + ii*sizeof(Fts3PhraseToken));
     347:         zTemp = fts3ReallocOrFree(zTemp, nTemp + nByte);
     348:         if( !zTemp || !p ){
     349:           rc = SQLITE_NOMEM;
     350:           goto getnextstring_out;
     351:         }
     352: 
     353:         assert( nToken==ii );
     354:         pToken = &((Fts3Phrase *)(&p[1]))->aToken[ii];
     355:         memset(pToken, 0, sizeof(Fts3PhraseToken));
     356: 
     357:         memcpy(&zTemp[nTemp], zByte, nByte);
     358:         nTemp += nByte;
     359: 
     360:         pToken->n = nByte;
     361:         pToken->isPrefix = (iEnd<nInput && zInput[iEnd]=='*');
     362:         pToken->bFirst = (iBegin>0 && zInput[iBegin-1]=='^');
     363:         nToken = ii+1;
     364:       }
     365:     }
     366:   }
     367: 
     368:   if( rc==SQLITE_DONE ){
     369:     int jj;
     370:     char *zBuf = 0;
     371: 
>>   372:     p = fts3ReallocOrFree(p, nSpace + nToken*sizeof(Fts3PhraseToken) + nTemp);
     373:     if( !p ){
     374:       rc = SQLITE_NOMEM;
     375:       goto getnextstring_out;
     376:     }
     377:     memset(p, 0, (char *)&(((Fts3Phrase *)&p[1])->aToken[0])-(char *)p);
     378:     p->eType = FTSQUERY_PHRASE;
     379:     p->pPhrase = (Fts3Phrase *)&p[1];
     380:     p->pPhrase->iColumn = pParse->iDefaultCol;
     381:     p->pPhrase->nToken = nToken;
     382: 
     383:     zBuf = (char *)&p->pPhrase->aToken[nToken];
     384:     assert( nTemp==0 || zTemp );
     385:     if( zTemp ){
     386:       memcpy(zBuf, zTemp, nTemp);
     387:     }
     388: 
     389:     for(jj=0; jj<p->pPhrase->nToken; jj++){
     390:       p->pPhrase->aToken[jj].z = zBuf;
     391:       zBuf += p->pPhrase->aToken[jj].n;
     392:     }
     393:     rc = SQLITE_OK;
     394:   }
     395: 
     396:  getnextstring_out:
     397:   if( pCursor ){
     398:     pModule->xClose(pCursor);
     399:   }
     400:   sqlite3_free(zTemp);
     401:   if( rc!=SQLITE_OK ){
     402:     sqlite3_free(p);
     403:     p = 0;
     404:   }
     405:   *ppExpr = p;
     406:   return rc;
     407: }

