     251: SQLITE_NOINLINE int sqlite3VdbeMemGrow(Mem *pMem, int n, int bPreserve){
     252:   assert( sqlite3VdbeCheckMemInvariants(pMem) );
     253:   assert( !sqlite3VdbeMemIsRowSet(pMem) );
     254:   testcase( pMem->db==0 );
     255: 
     256:   /* If the bPreserve flag is set to true, then the memory cell must already
     257:   ** contain a valid string or blob value.  */
     258:   assert( bPreserve==0 || pMem->flags&(MEM_Blob|MEM_Str) );
     259:   testcase( bPreserve && pMem->z==0 );
     260: 
     261:   assert( pMem->szMalloc==0
     262:        || (pMem->flags==MEM_Undefined 
     263:            && pMem->szMalloc<=sqlite3DbMallocSize(pMem->db,pMem->zMalloc))
     264:        || pMem->szMalloc==sqlite3DbMallocSize(pMem->db,pMem->zMalloc));
     265:   if( pMem->szMalloc>0 && bPreserve && pMem->z==pMem->zMalloc ){
     266:     if( pMem->db ){
     267:       pMem->z = pMem->zMalloc = sqlite3DbReallocOrFree(pMem->db, pMem->z, n);
     268:     }else{
>>   269:       pMem->zMalloc = sqlite3Realloc(pMem->z, n);
     270:       if( pMem->zMalloc==0 ) sqlite3_free(pMem->z);
     271:       pMem->z = pMem->zMalloc;
     272:     }
     273:     bPreserve = 0;
     274:   }else{
     275:     if( pMem->szMalloc>0 ) sqlite3DbFreeNN(pMem->db, pMem->zMalloc);
     276:     pMem->zMalloc = sqlite3DbMallocRaw(pMem->db, n);
     277:   }
     278:   if( pMem->zMalloc==0 ){
     279:     sqlite3VdbeMemSetNull(pMem);
     280:     pMem->z = 0;
     281:     pMem->szMalloc = 0;
     282:     return SQLITE_NOMEM_BKPT;
     283:   }else{
     284:     pMem->szMalloc = sqlite3DbMallocSize(pMem->db, pMem->zMalloc);
     285:   }
     286: 
     287:   if( bPreserve && pMem->z ){
     288:     assert( pMem->z!=pMem->zMalloc );
     289:     memcpy(pMem->zMalloc, pMem->z, pMem->n);
     290:   }
     291:   if( (pMem->flags&MEM_Dyn)!=0 ){
     292:     assert( pMem->xDel!=0 && pMem->xDel!=SQLITE_DYNAMIC );
     293:     pMem->xDel((void *)(pMem->z));
     294:   }
     295: 
     296:   pMem->z = pMem->zMalloc;
     297:   pMem->flags &= ~(MEM_Dyn|MEM_Ephem|MEM_Static);
     298:   return SQLITE_OK;
     299: }

