     491: static int vdbePmaReadBlob(
     492:   PmaReader *p,                   /* PmaReader from which to take the blob */
     493:   int nByte,                      /* Bytes of data to read */
     494:   u8 **ppOut                      /* OUT: Pointer to buffer containing data */
     495: ){
     496:   int iBuf;                       /* Offset within buffer to read from */
     497:   int nAvail;                     /* Bytes of data available in buffer */
     498: 
     499:   if( p->aMap ){
     500:     *ppOut = &p->aMap[p->iReadOff];
     501:     p->iReadOff += nByte;
     502:     return SQLITE_OK;
     503:   }
     504: 
     505:   assert( p->aBuffer );
     506: 
     507:   /* If there is no more data to be read from the buffer, read the next
     508:   ** p->nBuffer bytes of data from the file into it. Or, if there are less
     509:   ** than p->nBuffer bytes remaining in the PMA, read all remaining data.  */
     510:   iBuf = p->iReadOff % p->nBuffer;
     511:   if( iBuf==0 ){
     512:     int nRead;                    /* Bytes to read from disk */
     513:     int rc;                       /* sqlite3OsRead() return code */
     514: 
     515:     /* Determine how many bytes of data to read. */
     516:     if( (p->iEof - p->iReadOff) > (i64)p->nBuffer ){
     517:       nRead = p->nBuffer;
     518:     }else{
     519:       nRead = (int)(p->iEof - p->iReadOff);
     520:     }
     521:     assert( nRead>0 );
     522: 
     523:     /* Readr data from the file. Return early if an error occurs. */
     524:     rc = sqlite3OsRead(p->pFd, p->aBuffer, nRead, p->iReadOff);
     525:     assert( rc!=SQLITE_IOERR_SHORT_READ );
     526:     if( rc!=SQLITE_OK ) return rc;
     527:   }
     528:   nAvail = p->nBuffer - iBuf;
     529: 
     530:   if( nByte<=nAvail ){
     531:     /* The requested data is available in the in-memory buffer. In this
     532:     ** case there is no need to make a copy of the data, just return a
     533:     ** pointer into the buffer to the caller.  */
     534:     *ppOut = &p->aBuffer[iBuf];
     535:     p->iReadOff += nByte;
     536:   }else{
     537:     /* The requested data is not all available in the in-memory buffer.
     538:     ** In this case, allocate space at p->aAlloc[] to copy the requested
     539:     ** range into. Then return a copy of pointer p->aAlloc to the caller.  */
     540:     int nRem;                     /* Bytes remaining to copy */
     541: 
     542:     /* Extend the p->aAlloc[] allocation if required. */
     543:     if( p->nAlloc<nByte ){
     544:       u8 *aNew;
     545:       sqlite3_int64 nNew = MAX(128, 2*(sqlite3_int64)p->nAlloc);
     546:       while( nByte>nNew ) nNew = nNew*2;
>>   547:       aNew = sqlite3Realloc(p->aAlloc, nNew);
     548:       if( !aNew ) return SQLITE_NOMEM_BKPT;
     549:       p->nAlloc = nNew;
     550:       p->aAlloc = aNew;
     551:     }
     552: 
     553:     /* Copy as much data as is available in the buffer into the start of
     554:     ** p->aAlloc[].  */
     555:     memcpy(p->aAlloc, &p->aBuffer[iBuf], nAvail);
     556:     p->iReadOff += nAvail;
     557:     nRem = nByte - nAvail;
     558: 
     559:     /* The following loop copies up to p->nBuffer bytes per iteration into
     560:     ** the p->aAlloc[] buffer.  */
     561:     while( nRem>0 ){
     562:       int rc;                     /* vdbePmaReadBlob() return code */
     563:       int nCopy;                  /* Number of bytes to copy */
     564:       u8 *aNext = 0;              /* Pointer to buffer to copy data from */
     565: 
     566:       nCopy = nRem;
     567:       if( nRem>p->nBuffer ) nCopy = p->nBuffer;
     568:       rc = vdbePmaReadBlob(p, nCopy, &aNext);
     569:       if( rc!=SQLITE_OK ) return rc;
     570:       assert( aNext!=p->aAlloc );
     571:       assert( aNext!=0 );
     572:       memcpy(&p->aAlloc[nByte - nRem], aNext, nCopy);
     573:       nRem -= nCopy;
     574:     }
     575: 
     576:     *ppOut = p->aAlloc;
     577:   }
     578: 
     579:   return SQLITE_OK;
     580: }

